// Rust — multi-window Brain scaffold:
use std::sync::{Arc, Mutex};
use std::thread;

let shared_state = Arc::new(Mutex::new(AppState::default()));

// Window A — Main Dashboard
let state_a = Arc::clone(&shared_state);
thread::spawn(move || {
    let window_a = MainDashboard::new().unwrap();
    window_a.show().unwrap();
    slint::run_event_loop_until_quit().unwrap();
});

// Window B — Telemetry Bar
let state_b = Arc::clone(&shared_state);
thread::spawn(move || {
    let window_b = TelemetryBar::new().unwrap();
    window_b.show().unwrap();
    slint::run_event_loop_until_quit().unwrap();
});

// Brain event loop — coordinates both windows
slint::run_event_loop().unwrap();
